parameters.query:
SELECT id, email, name FROM users
WHERE created_at < CURRENT_DATE - INTERVAL '7 days'
ORDER BY created_at ASC;

parameters.jsCode:
const stats = $input.item.json;
const user  = $('Loop Over Users').item.json;

const insights = [];

// Completion rate
if (stats.completion_rate >= 80) {
  insights.push(`🌟 Excellent! You finished ${stats.completion_rate}% of your tasks this week.`);
} else if (stats.completion_rate >= 60) {
  insights.push(`👍 Good progress — ${stats.completion_rate}% of tasks completed.`);
} else if (stats.total_tasks > 0) {
  insights.push(`💪 Only ${stats.completion_rate}% completed. Consider breaking big tasks into smaller ones.`);
}

// On-time rate
if (stats.on_time_rate >= 90) {
  insights.push(`⏰ Outstanding punctuality — ${stats.on_time_rate}% completed on time.`);
} else if (stats.on_time_rate !== null && stats.on_time_rate < 70) {
  insights.push(`📅 ${stats.on_time_rate}% on-time rate. Try setting more realistic deadlines.`);
}

// AI confidence
if (stats.avg_confidence !== null && stats.avg_confidence < 75) {
  insights.push('💭 Your task descriptions could be more specific — this helps the AI extract better data.');
}

// Volume
if (stats.total_tasks === 0) {
  insights.push('🚀 No tasks logged this week. Try capturing even small to-dos!');
} else if (stats.total_tasks >= 20) {
  insights.push(`📈 High-volume week — ${stats.total_tasks} tasks created. Great hustle!`);
}

return [{
  json: {
    user_id:         user.id,
    user_name:       user.name || 'there',
    user_email:      user.email,
    total_tasks:     stats.total_tasks     || 0,
    completed:       stats.completed       || 0,
    still_active:    stats.still_active    || 0,
    on_time_rate:    stats.on_time_rate    || 0,
    completion_rate: stats.completion_rate || 0,
    high_priority:   stats.high_priority   || 0,
    avg_confidence:  stats.avg_confidence  || 0,
    insights
  }
}];
